std::string normalizeURL(std::string url) {
    // Add default protocol if missing
    if (url.find("://") == std::string::npos) {
        url = "http://" + url;
    }

    // Convert protocol to lowercase
    size_t protocolEnd = url.find("://");
    if (protocolEnd != std::string::npos) {
        for (size_t i = 0; i < protocolEnd; ++i) {
            url[i] = std::tolower(url[i]);
        }
    }

    // Find query parameters section
    size_t paramStart = url.find('?');
    if (paramStart != std::string::npos && paramStart + 1 < url.length()) {
        std::string baseUrl = url.substr(0, paramStart + 1);
        std::string paramString = url.substr(paramStart + 1);

        // Parse parameters
        std::vector<std::pair<std::string, std::string>> params;
        std::istringstream paramStream(paramString);
        std::string param;

        while (std::getline(paramStream, param, '&')) {
            size_t equalPos = param.find('=');
            if (equalPos != std::string::npos) {
                std::string name = param.substr(0, equalPos);
                std::string value = param.substr(equalPos + 1);
                params.push_back({name, value});
            } else {
                params.push_back({param, ""});
            }
        }

        // Sort parameters by name
        std::sort(params.begin(), params.end());

        // Reconstruct URL with sorted parameters
        std::string result = baseUrl;
        for (size_t i = 0; i < params.size(); ++i) {
            result += (i > 0 ? "&" : "") + params[i].first;
            if (!params[i].second.empty()) {
                result += "=" + params[i].second;
            }
        }
        return result;
    }

    return url;
}

